// NORMALIZADOR INPUT V18
let body = $input.item.json.body || {};
let data = body.data || {};
let msg = data.message || {};

let userMessage = "";
if (msg.extendedTextMessage && msg.extendedTextMessage.text) {
    userMessage = msg.extendedTextMessage.text;
}
else if (msg.conversation) {
    userMessage = msg.conversation;
}
else if (msg.conversationMessage && msg.conversationMessage.message) {
    userMessage = msg.conversationMessage.message;
}
else if (body.message) {
    userMessage = body.message;
}

if (!userMessage) userMessage = "Hola";

return {
  json: {
    ...$input.item.json,
    user_message: userMessage
  }
};

// FILTRO V7 ULTRA ROBUSTO
let inputData = $input.item.json.response || $input.item.json.text || "";
let rawRemoteJid = "";
try {
    if ($('Webhook').item.json.body.data && $('Webhook').item.json.body.data.key) {
        rawRemoteJid = $('Webhook').item.json.body.data.key.remoteJid;
    }
    else if ($('Webhook').item.json.body.key) {
        rawRemoteJid = $('Webhook').item.json.body.key.remoteJid;
    }
} catch (e) {}

let textoVoz = "";
let accionFinal = "info";
let mensajeTexto = "";

if (typeof inputData === 'string') {
    let clean = inputData.replace(/```json/g, "").replace(/```/g, "").trim();
    try {
        let parsed = JSON.parse(clean);
        textoVoz = parsed.respuesta_voz || clean;
        accionFinal = parsed.accion_requerida || "info";
    } catch(e) { textoVoz = clean; }
} else { 
    textoVoz = inputData.respuesta_voz || "";
    accionFinal = inputData.accion_requerida || "info";
}

// Detección Idioma
function detectLang(t) {
    if (t.includes("der") || t.includes("die")) return "de";
    if (t.includes("the") || t.includes("have")) return "en";
    if (t.includes("il") || t.includes("ciao")) return "it";
    return "es";
}
let lang = detectLang(textoVoz);
const voices = {
    de: { lc: "de-DE", name: "de-DE-Neural2-F", g: "FEMALE" },
    en: { lc: "en-US", name: "en-US-Neural2-F", g: "FEMALE" },
    es: { lc: "es-US", name: "es-US-Neural2-B", g: "MALE" },
    it: { lc: "it-IT", name: "it-IT-Neural2-A", g: "FEMALE" }
};
const v = voices[lang] || voices.es;

if (accionFinal === "agendar") mensajeTexto = "🔗 Agenda aquí: https://cal.com/example";

return {
    json: {
        clean_voice: textoVoz.replace(/[^\w\s.,!?áéíóú]/g, " "),
        accion: accionFinal,
        mensaje_texto: mensajeTexto,
        remote_jid: rawRemoteJid,
        tts_language_code: v.lc,
        tts_voice_name: v.name,
        tts_gender: v.g
    }
};
